4549   // (X & Y) != 0 ? X : X & ~Y  --> X
4550   if (TrueVal == X && match(FalseVal, m_And(m_Specific(X), m_APInt(C))) &&
4551       *Y == ~*C)
4552     return TrueWhenUnset ? FalseVal : TrueVal;
