2542   // (A & C1)|(B & C2)
2543   Value *A, *B;
2544   const APInt *C1, *C2;
2545   if (match(Op0, m_And(m_Value(A), m_APInt(C1))) &&
2546       match(Op1, m_And(m_Value(B), m_APInt(C2)))) {
2547     if (*C1 == ~*C2) {
2548       // (A & C1)|(B & C2)
2549       // If we have: ((V + N) & C1) | (V & C2)
2550       // .. and C2 = ~C1 and C2 is 0+1+ and (N & C2) == 0
2551       // replace with V+N.
2552       Value *N;
2553       if (C2->isMask() && // C2 == 0+1+
2554           match(A, m_c_Add(m_Specific(B), m_Value(N)))) {
2555         // Add commutes, try both ways.
2556         if (MaskedValueIsZero(N, *C2, Q.DL, 0, Q.AC, Q.CxtI, Q.DT))
2557           return A;
2558       }
2559       // Or commutes, try both ways.
2560       if (C1->isMask() && match(B, m_c_Add(m_Specific(A), m_Value(N)))) {
2561         // Add commutes, try both ways.
2562         if (MaskedValueIsZero(N, *C1, Q.DL, 0, Q.AC, Q.CxtI, Q.DT))
2563           return B;
2564       }
2565     }
2566   }
2567 
2568   // If the operation is with the result of a phi instruction, check whether
2569   // operating on all incoming values of the phi always yields the same value.
2570   if (isa<PHINode>(Op0) || isa<PHINode>(Op1))
2571     if (Value *V = threadBinOpOverPHI(Instruction::Or, Op0, Op1, Q, MaxRecurse))
2572       return V;
2573 
2574   if (Op0->getType()->isIntOrIntVectorTy(1)) {
2575     if (std::optional<bool> Implied =
2576             isImpliedCondition(Op0, Op1, Q.DL, false)) {
2577       // If Op0 is false implies Op1 is false, then Op1 is a subset of Op0.
2578       if (*Implied == false)
2579         return Op0;
2580       // If Op0 is false implies Op1 is true, then at least one is always true.
2581       if (*Implied == true)
2582         return ConstantInt::getTrue(Op0->getType());
2583     }
2584     if (std::optional<bool> Implied =
2585             isImpliedCondition(Op1, Op0, Q.DL, false)) {
2586       // If Op1 is false implies Op0 is false, then Op0 is a subset of Op1.
2587       if (*Implied == false)
2588         return Op1;
2589       // If Op1 is false implies Op0 is true, then at least one is always true.
2590       if (*Implied == true)
2591         return ConstantInt::getTrue(Op1->getType());
2592     }
2593   }
2594 
2595   if (Value *V = simplifyByDomEq(Instruction::Or, Op0, Op1, Q, MaxRecurse))
2596     return V;
2597 
2598   return nullptr;
2599 }
