2187   // check that one of the multipliers is not zero, we can omit the 'and', and
2188   // only keep the overflow check.
2189   if (isCheckForZeroAndMulWithOverflow(Op0, Op1, true))
2190     return Op1;
2191   if (isCheckForZeroAndMulWithOverflow(Op1, Op0, true))
2192     return Op0;
2193 
2194   // A & (-A) = A if A is a power of two or zero.
2195   if (match(Op0, m_Neg(m_Specific(Op1))) ||
2196       match(Op1, m_Neg(m_Specific(Op0)))) {
2197     if (isKnownToBeAPowerOfTwo(Op0, Q.DL, /*OrZero*/ true, 0, Q.AC, Q.CxtI,
2198                                Q.DT))
2199       return Op0;
2200     if (isKnownToBeAPowerOfTwo(Op1, Q.DL, /*OrZero*/ true, 0, Q.AC, Q.CxtI,
2201                                Q.DT))
